class Solution:
    def longestStrChain(self, words):
        wset = set(words)
        from functools import lru_cache
        import sys
        sys.setrecursionlimit(10000)
        @lru_cache(maxsize=None)
        def chain(w):
            best = 1
            for i in range(len(w)):
                pred = w[:i] + w[i + 1:]
                if pred in wset:
                    best = max(best, 1 + chain(pred))
            return best
        return max(chain(w) for w in wset)

