class Solution:
    def longestStrChain(self, words):
        words = sorted(set(words), key=len)
        best = {}
        ans = 1
        for w in words:
            cur = 1
            for i in range(len(w)):
                pred = w[:i] + w[i + 1:]
                if pred in best:
                    cur = max(cur, best[pred] + 1)
            best[w] = cur
            ans = max(ans, cur)
        return ans

